package org.apache.commons.csv;

import static org.junit.jupiter.api.Assertions.*;
import static org.mockito.Mockito.*;

import java.io.File;
import java.io.IOException;
import java.nio.charset.Charset;

import org.apache.commons.csv.CSVFormat;
import org.apache.commons.csv.CSVPrinter;
import org.junit.jupiter.api.BeforeEach;
import org.junit.jupiter.api.Test;

class CSVFormatPrintTest {

    private CSVFormat csvFormat;
    private File mockFile;
    private Charset charset;

    @BeforeEach
    void setUp() {
        csvFormat = CSVFormat.DEFAULT;
        mockFile = mock(File.class);
        charset = Charset.forName("UTF-8");
    }

    @Test
    void testPrintCreatesCSVPrinter() throws Exception {
        // Create a mock CSVPrinter
        CSVPrinter mockPrinter = mock(CSVPrinter.class);

        // Spy on CSVFormat to override print(File, Charset) method to return mockPrinter
        CSVFormat spyFormat = spy(csvFormat);

        doReturn(mockPrinter).when(spyFormat).print(any(File.class), any(Charset.class));

        CSVPrinter printer = spyFormat.print(mockFile, charset);

        assertNotNull(printer);
        assertSame(mockPrinter, printer);
    }

    @Test
    void testPrintThrowsIOException() throws IOException {
        // Create a CSVFormat instance that throws IOException in print(File, Charset)
        CSVFormat csvFormatIOException = new CSVFormat.Builder(CSVFormat.DEFAULT)
                .setPrintFunction((file, cs) -> {
                    throw new IOException("Simulated IOException");
                })
                .build();

        IOException thrown = assertThrows(IOException.class, () -> {
            csvFormatIOException.print(mockFile, charset);
        });
        assertEquals("Simulated IOException", thrown.getMessage());
    }
}
```

---

**Note:**  
If your version of `CSVFormat` does not have a `Builder` or `setPrintFunction` method, then since `CSVFormat` is final and cannot be subclassed, you cannot override its methods normally. Instead, you can mock it with Mockito:

```java
    @Test
    void testPrintThrowsIOException() throws IOException {
        CSVFormat mockFormat = mock(CSVFormat.class);
        when(mockFormat.print(any(File.class), any(Charset.class))).thenThrow(new IOException("Simulated IOException"));

        IOException thrown = assertThrows(IOException.class, () -> {
            mockFormat.print(mockFile, charset);
        });
        assertEquals("Simulated IOException", thrown.getMessage());
    }
```

